var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제5방위선 함락 후, 175시간 경과","JPN":"第5防衛線陥落後、175時間経過","ENG":"175 hours after the fall of the 5th Defense Line","TWN":"第五防線淪陷後經過175小時","THA":"175 ชั่วโมงหลังจากการล่มสลายของแนวป้องกันที่ 5","VTN":"175 giờ sau khi Phòng Tuyến thứ 5 thất thủ","SCN":"第5防线沦陷，175小时后","DEU":"175 Stunden nach dem Fall der 5. Verteidigungslinie","FRA":"175 heures après la chute de la 5e ligne de défense"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제4 방위선\\n<color=#ffd34c>제2 차 아포리아 공략 작전</color>","JPN":"人類統合防衛軍第4防衛線\\n<color=#ffd34c>第2次アポリア攻略作戦</color>","ENG":"[[","TWN":"人類共同保衛軍第四防線\\n<color=#ffd34c>第二波攻陷阿波利亞作戰</color>","THA":"แนวป้องกันที่ 4 กองกำลังป้องกันมนุษยสหชาติ\\n<color=#ffd34c>ปฏิบัติการกำจัดอาโพเรีย ครั้งที่ 2</color>","VTN":"Phòng Tuyến thứ 4 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất\\n<color=#ffd34c>Chiến dịch Aporia, lần thử thứ 2</color>","SCN":"人类综合防卫军第4防线\\n<color=#ffd34c>第2次阿波利亚作战</color>","DEU":"4. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit\\n<color=#ffd34c>Operation „Aporia – Der 2. Versuch“</color>","FRA":"4e ligne de défense des Forces de défense unies de l'humanité\\n<color=#ffd34c>2e tentative de l'opération Aporia</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 대원, 작전에 앞서 짧게 브리핑하겠습니다.","JPN":"隊員の皆さん、作戦開始に当たり手短に事前説明を行います。","ENG":"All units, I will do a short briefing before we commence this operation.","TWN":"全體隊員，作戰前我簡單說明一下。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"본 작전의 목표는 크로스로드 작전과 마찬가지로, 세계를 유린하는 아포리아를 사람이 살지 않는 고심도 이면세계로 추방하는 것입니다.","JPN":"本作戦の目標はクロスロード作戦同様、世界を蹂躙するアポリアを誰もいない高深度裏世界に追放することです。","ENG":"This operation's objective will be identical to that of Operation Crossroads. It is to exile Aporia, who has infiltrated our world, to the hyperdepths of Counterside where no human resides.","TWN":"本次作戰的目標與十字路口作戰時一樣，我們要將踐踏這個世界的阿波利亞驅逐至人類無法生存的高深度異界。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"다만, 이전 작전과는 달리 현 전력으로는 아포리아를 차원통로로 직접 유도하는 것이 불가능합니다.","JPN":"ただし、前回の作戦とは異なり、現在の戦力ではアポリアを次元通路に直接誘導することはできません。","ENG":"However, unlike our previous operation, luring Aporia to the dimensional passage is considered impossible with our current manpower.","TWN":"但與之前的作戰不同，就我們目前的實力而言，不可能直接將阿波利亞引誘至次元通道。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"따라서 제4 방위선의 모든 전력을 끌어 모은 고출력 빔 병기로 초장거리 저격을 수행.","JPN":"よって、第4防衛線の全電力を集約した高出力ビーム兵器を使用し、超長距離狙撃を遂行。","ENG":"Accordingly, we are going to fire the high-powered beam weapon from afar using all of the electricity of the 4th Defense Line.","TWN":"所以，要將第四防線的所有電力集中到高輸出電波武器中，進行超遠距離的狙擊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아포리아가 핵을 흡수하는 순간을 노려, 고치와 함께 차원통로로 떨어트릴 것입니다.","JPN":"アポリアが核を吸収する瞬間を狙い、繭もろとも次元通路に突き落とします。","ENG":"When Aporia is consuming a core, we will strike and send Aporia and cocoons into the dimensional passage.","TWN":"瞄準阿波利亞吸收核心的那個瞬間，將他與繭一起丟入次元通道。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 왠지 크로스로드 작전 때보다 훨씬 터프한 것 같은데요?","JPN":"ハハ、何だかクロスロード作戦のときよりずっとタフになっていませんか？","ENG":"Hah hah, sounds like operation's gonna be rougher than Crossroads, no?","TWN":"哈哈，怎麼感覺比十字路口的時候更難了？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이번에도 아포리아는 고치 관측소와 그 주변의 고치부터 노려올 것입니다.","JPN":"今回もアポリアは繭観測所とその周辺の繭を先に狙ってくるでしょう。","ENG":"Aporia will come for the cocoons at the observatory and its vicinity first.","TWN":"這次預計阿波利亞也會優先襲擊繭觀測站及其周圍的繭。"},"stage":{"bg":"MAINSTREAM_5201001","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이에 따라, 다이브 요원은 사전에 고심도 다이브를 수행.","JPN":"以上を踏まえ、ダイブ要員は事前に高深度ダイブを遂行。","ENG":"So, dive agents should be prepared for hyperdepth diving in advance.","TWN":"因此，躍入的人需要預先執行高深度的躍入。"},"stage":{"bg":"MAINSTREAM_5201001","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사전에 정해 둔 시간에 이면세계로 통하는 차원통로를 연결해주시면 됩니다만.","JPN":"所定の時間になったら、裏世界へ通じる次元通路を繋げてくださればいいのですが。","ENG":"All you need to do is connect the passageway to Counterside at a predetermined time.","TWN":"要在事先定好的時間內，連接通往異界的次元通道。"},"stage":{"bg":"MAINSTREAM_5201001","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"정말로 괜찮으시겠습니까, 크로펠 부관님?","JPN":"本当に大丈夫ですか、クロペル副官？","ENG":"But are you sure about this, Adjutant Kropel?","TWN":"真的沒問題嗎，婕娜副官？"},"stage":{"bg":"MAINSTREAM_5201001","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저희가 할 말은 아니지만, 우리 세계의 차원통로 기술은 굉장히 불안정합니다.","JPN":"私たちが言うのもなんですが、この世界の次元通路技術はあまり安定していません。","ENG":"I'm afraid to say that this world's technology for connecting dimensional passages is very unstable.","TWN":"雖然我不該說這樣的話，但我們世界的次元通道技術相當不穩定。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"자칫 잘못하면, 그대로 허수공간에 빠져버릴 수도 있어요.","JPN":"もし間違えたら、そのまま虚数空間に落ちる可能性もあります。","ENG":"One slip-up and you might fall right into the imaginary space.","TWN":"稍有不慎，就有可能會陷入虛數空間。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네피림과 함께 차원통로에 떨어진 대령님이 그쪽 세계에 나타나지 않았던 이유 역시…….","JPN":"ネフィリムと共に次元通路に落ちた大佐がそちらの世界に現れなかった理由もやはり……","ENG":"Perhaps the reason why Colonel didn't appear on that world when he jumped in with the Nephil is because...","TWN":"與諾菲力一起墜入次元通道的上校，沒有出現在那邊世界的原因也是因為……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};